using System.Data; using Dapper; using Microsoft.Extensions.Configuration; using Microsoft.Extensions.Logging; using Npgsql;
namespace Valora.Infrastructure.Database;
public interface IDbConnectionFactory{ IDbConnection Create(); }
public sealed class PostgresConnectionFactory(IConfiguration cfg):IDbConnectionFactory{ public IDbConnection Create()=>new NpgsqlConnection(cfg.GetConnectionString("DefaultConnection")); }
public sealed class MigrationRunner(IDbConnectionFactory factory, ILogger<MigrationRunner> logger){
 public async Task<IReadOnlyList<string>> RunAsync(string root){ var dir=Path.Combine(root,"database","postgresql"); var files=Directory.GetFiles(dir,"*.sql").OrderBy(x=>x).ToList(); using var c=factory.Create(); c.Open(); await c.ExecuteAsync("CREATE SCHEMA IF NOT EXISTS valora; CREATE TABLE IF NOT EXISTS valora.schema_migrations(script_name text PRIMARY KEY, applied_at timestamptz NOT NULL DEFAULT now());"); var done=(await c.QueryAsync<string>("SELECT script_name FROM valora.schema_migrations")).ToHashSet(); var applied=new List<string>(); foreach(var f in files){ var name=Path.GetFileName(f); if(done.Contains(name)) continue; using var tx=c.BeginTransaction(); try{ await c.ExecuteAsync(await File.ReadAllTextAsync(f), transaction:tx); await c.ExecuteAsync("INSERT INTO valora.schema_migrations(script_name) VALUES (@name)",new{name},tx); tx.Commit(); applied.Add(name); logger.LogInformation("Migration {Migration} aplicada",name);} catch(Exception ex){ tx.Rollback(); logger.LogError(ex,"Erro na migration {Migration}",name); throw; }} return applied; }
}
